import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.CZqXuAiL.js";const k=JSON.parse('{"title":"SYNPROXY","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/detection-engine/synproxy.md","filePath":"openshield-xdp/detection-engine/synproxy.md","lastUpdated":1782455743000}'),n={name:"openshield-xdp/detection-engine/synproxy.md"};function o(l,e,c,r,d,p){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="synproxy" tabindex="-1">SYNPROXY <a class="header-anchor" href="#synproxy" aria-label="Permalink to &quot;SYNPROXY&quot;">​</a></h1><p>Cookie-based SYN flood mitigation at XDP line rate. When a TCP SYN arrives, OpenShield generates a cryptographic cookie, sends a SYN-ACK back to the client via <code>XDP_TX</code>, and only passes the connection to the kernel after the client returns a valid ACK with the cookie.</p><div class="tip custom-block"><p class="custom-block-title">When to enable</p><p>Enable SYNPROXY when your server is under sustained TCP SYN floods that saturate connection tracking. Disabled by default — test against your traffic profile before enabling in production.</p></div><h2 id="packet-flow" tabindex="-1">Packet flow <a class="header-anchor" href="#packet-flow" aria-label="Permalink to &quot;Packet flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                OpenShield (XDP)              Server (kernel)</span></span>
<span class="line"><span>  |                         |                            |</span></span>
<span class="line"><span>  |--- SYN (seq=C) --------&gt;|                            |</span></span>
<span class="line"><span>  |                         |-- compute cookie ---------&gt;|</span></span>
<span class="line"><span>  |&lt;-- SYN-ACK (seq=cookie, ack=C+1) ---|                |</span></span>
<span class="line"><span>  |                         |                            |</span></span>
<span class="line"><span>  |--- ACK (ack=cookie+1) -&gt;|                            |</span></span>
<span class="line"><span>  |                         |-- verify cookie ----------&gt;|</span></span>
<span class="line"><span>  |                         |-- XDP_PASS (reinject SYN)-&gt;|</span></span>
<span class="line"><span>  |                         |                            |--- real handshake ---</span></span></code></pre></div><ol><li>Client sends SYN (<code>S → D</code>, seq=<code>C</code>)</li><li>OpenShield computes <code>cookie = SplitMix64(secret ^ timestamp ^ 5-tuple)</code></li><li>Rewrites packet: swaps MAC/IP, sets flags <code>SYN|ACK</code>, seq=<code>cookie_hi32</code>, ack_seq=<code>C+1</code>, window=65535, recomputes TCP checksum</li><li>Sends <code>XDP_TX</code> back to client</li><li>Stores <code>{cookie, client_seq, expires_at}</code> in <code>syn_cookie_map</code> (LRU_HASH, 100K entries)</li><li>Client ACKs (<code>ack_seq = cookie_hi32 + 1</code>)</li><li>Extracts <code>cookie_hi32 = ack_seq - 1</code>, checks expiry, recomputes expected cookie</li><li>Match → <code>XDP_PASS</code> (kernel completes real handshake with original SYN parameters)</li><li>Mismatch → <code>XDP_DROP</code></li></ol><h2 id="cookie-structure" tabindex="-1">Cookie structure <a class="header-anchor" href="#cookie-structure" aria-label="Permalink to &quot;Cookie structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cookie = SplitMix64(secret ^ timestamp_sec ^ saddr ^ daddr ^ sport ^ dport)</span></span>
<span class="line"><span>cookie_hi32 = timestamp_sec   ← expiry detectable without map lookup</span></span>
<span class="line"><span>cookie_lo32 = hash &amp; 0xFFFFFFFF</span></span></code></pre></div><p>SplitMix64 is constant-time and branchless: 3 XOR + 3 multiply/shift (~30 BPF instructions).</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dynamic</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  synproxy_enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Master switch</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  synproxy_secret</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # Hex string or empty (auto-derived at load)</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  synproxy_timeout_sec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Cookie validity (seconds)</span></span></code></pre></div><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limitation</th><th>Detail</th></tr></thead><tbody><tr><td>IPv4 only</td><td>IPv6 header layout differs; not yet supported</td></tr><tr><td>TCP options</td><td>MSS, window scaling, SACK not reflected in SYN-ACK. Kernel re-sends original SYN with all options after cookie passes</td></tr><tr><td>Not stateful</td><td>Each cookie is independent. No connection rate limiting within SYNPROXY itself</td></tr><tr><td>Secret rotation</td><td>Userspace generates a new secret at load time. Stale cookies are invalidated</td></tr></tbody></table><h2 id="common-problems" tabindex="-1">Common problems <a class="header-anchor" href="#common-problems" aria-label="Permalink to &quot;Common problems&quot;">​</a></h2><h3 id="synproxy-enabled-but-syn-floods-still-hitting-the-server" tabindex="-1">&quot;SYNPROXY enabled but SYN floods still hitting the server&quot; <a class="header-anchor" href="#synproxy-enabled-but-syn-floods-still-hitting-the-server" aria-label="Permalink to &quot;&quot;SYNPROXY enabled but SYN floods still hitting the server&quot;&quot;">​</a></h3><p>Check that <code>xdp_mode</code> is <code>native</code> (not <code>generic</code>). Generic/SKB mode may not support <code>XDP_TX</code>.</p><h3 id="legitimate-connections-failing-after-enabling-synproxy" tabindex="-1">&quot;Legitimate connections failing after enabling SYNPROXY&quot; <a class="header-anchor" href="#legitimate-connections-failing-after-enabling-synproxy" aria-label="Permalink to &quot;&quot;Legitimate connections failing after enabling SYNPROXY&quot;&quot;">​</a></h3><p>Increase <code>synproxy_timeout_sec</code> if clients are on high-latency links. Check that your kernel version supports <code>XDP_TX</code> rewriting (≥ 5.15 recommended).</p><h2 id="related-pages" tabindex="-1">Related pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related pages&quot;">​</a></h2><p><a href="/pingless-studios-docs/openshield-xdp/detection-engine/overview">Detection Engine Overview</a> · <a href="/pingless-studios-docs/openshield-xdp/mitigation/overview">Mitigation Overview</a></p>`,20)])])}const u=a(n,[["render",o]]);export{k as __pageData,u as default};
